import{_ as i,o as c,c as a,ae as r}from"./chunks/framework.D4EcyEfM.js";const h=JSON.parse('{"title":"Scoring","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scoring.md","filePath":"guide/scoring.md"}'),o={name:"guide/scoring.md"};function n(t,e,s,d,l,m){return c(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="scoring" tabindex="-1">Scoring <a class="header-anchor" href="#scoring" aria-label="Permalink to &quot;Scoring&quot;">​</a></h1><p>Hybrid retrieval ranks memories using a weighted score:</p><p><code>final = semantic * w_semantic + recency * w_recency + importance * w_importance</code></p><p>Default weights (if unspecified):</p><ul><li><code>semantic</code>: <code>0.7</code></li><li><code>recency</code>: <code>0.2</code></li><li><code>importance</code>: <code>0.1</code></li></ul><h2 id="importance-score" tabindex="-1">Importance Score <a class="header-anchor" href="#importance-score" aria-label="Permalink to &quot;Importance Score&quot;">​</a></h2><p><code>importanceScore</code> is a <code>0..1</code> value on each memory. Higher values boost ranking and influence lifecycle behavior (for example distillation decisions in episodic memory).</p><h2 id="recency-score" tabindex="-1">Recency Score <a class="header-anchor" href="#recency-score" aria-label="Permalink to &quot;Recency Score&quot;">​</a></h2><p>Recency decays over time. A common interpretation is exponential decay with a 7-day half-life:</p><p><code>recency(t) = 0.5 ^ (age_days / 7)</code></p><p>This preserves recent relevance without discarding older high-signal memory.</p><h2 id="semantic-score" tabindex="-1">Semantic Score <a class="header-anchor" href="#semantic-score" aria-label="Permalink to &quot;Semantic Score&quot;">​</a></h2><p>Semantic relevance is computed from embedding similarity (cosine-style similarity from nearest-neighbor vector search).</p><h2 id="hybrid-ranking-in-practice" tabindex="-1">Hybrid Ranking in Practice <a class="header-anchor" href="#hybrid-ranking-in-practice" aria-label="Permalink to &quot;Hybrid Ranking in Practice&quot;">​</a></h2><p>When you query <code>POST /memories/query</code> or <code>db.memories.search(...)</code>:</p><ul><li>semantic match finds related content</li><li>recency favors newer events</li><li>importance keeps high-value memory ranked</li></ul><p>Tune weights per use case with <code>weights</code> in query options.</p>',17)])])}const u=i(o,[["render",n]]);export{h as __pageData,u as default};
